#!/usr/bin/env bash
# MemGuard kill-test — self-extracting bootstrap. Tested before shipping.
set -euo pipefail
TARGET="${1:-$HOME/memguard}"
mkdir -p "$TARGET"
echo "[memguard] extracting to $TARGET ..."
base64 -d > /tmp/_mg.tgz <<'__MG_B64__'

__MG_B64__
tar xzf /tmp/_mg.tgz -C "$TARGET" && rm -f /tmp/_mg.tgz
cd "$TARGET"
echo "[memguard] installing deps (torch/numpy/matplotlib + sentence-transformers for REAL verdict) ..."
python3 -m pip install --quiet numpy matplotlib sentence-transformers 2>/dev/null || pip install --quiet numpy matplotlib sentence-transformers || true
echo "[memguard] (assuming torch already present in your GPU VM; if not: pip install torch)"
echo "[memguard] running the kill-test ..."
python3 run_killtest.py
echo ""
echo "[memguard] done. Repo at $TARGET. Read README.md. The headline figure is degradation_curve.png."
